using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public class ChargeTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new Payments.PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeId_PerCall()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -5.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NullCardToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_VeryLargeAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 1_000_001m);

        Assert.IsFalse(result.Success);
    }
}

[TestClass]
public class RefundTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new Payments.PaymentGateway();
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_ReturnsUniqueRefundId()
    {
        var charge1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var charge2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);
        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_InvalidChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_DuplicateRefund_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        var duplicate = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(duplicate.Success);
    }
}

