using System.Collections.Concurrent;

namespace Payments;

public sealed class PaymentGateway
{
    private const decimal MaxChargeAmount = 1_000_000m;
    private readonly ConcurrentDictionary<string, bool> _charges = new();
    private readonly ConcurrentDictionary<string, bool> _refundedCharges = new();

    public Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        ArgumentNullException.ThrowIfNull(cardToken);
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token cannot be empty.", nameof(cardToken));

        if (amount <= 0 || amount > MaxChargeAmount)
            return Task.FromResult(new ChargeResult(string.Empty, false));

        var chargeId = $"ch_{Guid.NewGuid():N}";
        _charges[chargeId] = true;
        return Task.FromResult(new ChargeResult(chargeId, true));
    }

    public Task<RefundResult> RefundAsync(string chargeId)
    {
        ArgumentNullException.ThrowIfNull(chargeId);
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID cannot be empty.", nameof(chargeId));

        if (!_charges.ContainsKey(chargeId))
            return Task.FromResult(new RefundResult(string.Empty, false));

        if (!_refundedCharges.TryAdd(chargeId, true))
            return Task.FromResult(new RefundResult(string.Empty, false));

        var refundId = $"re_{Guid.NewGuid():N}";
        return Task.FromResult(new RefundResult(refundId, true));
    }
}

public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);

